import { SelectionToDomain } from './tools/selection-to-domain';
import { d3_ascending } from '../../../core/d3-constants';
import { mathMax, mathMin } from '../../../core/zc-constants';
import { defined } from '../../../utils/zcutils';
import { getEmptyDomain } from '../../../brush/chart-helpers/domain-helpers';

/**
 *
 * @param instanceMap
 * @param type
 * @param selection
 * @return {{x: {domain: *[], dataType: *, index: number}}}
 * @constructor
 */
export function BrushScrollDataFinder(instanceMap, type, selection, donotFixDomain) {
    let eventManager = this,
        scrollInstance = instanceMap.instance,
        chart = eventManager.chart.overview || eventManager.chart,
        dataType = chart.dataset.getDataType('x', 0),
        rotated = chart.axes.rotated,
        reversed = chart.axes.x.reversed,
        range = instanceMap.instance.brushScale.range(),
        s2 = fixOuterPadding(selection, range, rotated, reversed),
        domain = SelectionToDomain(s2, scrollInstance.brushScale, 'x', dataType, rotated, chart.axes.x.reversed, eventManager.chart);
        scrollInstance.actualScrollSelection = domain.slice(0);
        if (!domain.length) {
            var _d = getEmptyDomain(s2, chart.axes.x.scale, 'x', dataType, rotated, chart.axes.x.reversed, eventManager.chart);
            eventManager.chart.emptySelectionDomain = !_d ? eventManager.chart.emptySelectionDomain : _d;
        }
    // in caseof more domain

    if (defined(scrollInstance.visiblePointCount) && domain.length > scrollInstance.visiblePointCount) {
        domain.length = scrollInstance.visiblePointCount;
    }

    // fix min and max range
    let { minRange, maxRange } = eventManager.chart.systemConf.chart.axes.xaxis,
        fixDate = r => (domain[0] instanceof Date ? new Date(r) : r);

    if (defined(maxRange) || defined(minRange)) {
        eventManager.chart.scrollView = domain.slice(0);
    }

    let index = domain[1] > domain[0] ? { max: 1, min: 0 } : { max: 0, min: 0 };
    if (defined(maxRange) && !donotFixDomain) {
        domain[index.max] = fixDate(maxRange);
    }
    if (defined(minRange) && !donotFixDomain) {
        domain[index.min] = fixDate(minRange);
    }

    return { x: { domain, index: 0, dataType: dataType } };
}

/**
 *
 * @param {[number, number]} range
 * @param {[number, number]} selection
 * @return {*}
 */
export function fixOuterPadding(selection, range, axisrotated, axisreversed) {
    selection = selection.slice(0);

    // axes rotated
    if (range[0] > range[1]) {
        let [t0, t1] = range;
        range = [t1, t0];
    }
    range = range.slice(0).sort(d3_ascending);
    let adjust1 = mathMin(selection[0] - range[0], 0),
        adjust2 = mathMax(selection[1] - range[1], 0);

    // if((axisrotated && !axisreversed) || (!axisrotated && axisreversed)){
    //     selection[0] -= adjust1;
    //     selection[1] -= adjust2;
    // }else{
    //     selection[0] -= adjust1;
    //     selection[1] -= adjust2;
    // }

    // selection[0] -= adjust2;
    //   selection[1] -= adjust1;

    return selection;
}
